import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"Ein Projekt erstellen","description":"Eine Schritt-für-Schritt-Anleitung, wie man ein neues Mod-Projekt mit dem Fabric Vorlagen Mod Generator erstellt.","frontmatter":{"title":"Ein Projekt erstellen","description":"Eine Schritt-für-Schritt-Anleitung, wie man ein neues Mod-Projekt mit dem Fabric Vorlagen Mod Generator erstellt.","authors":["IMB11","Cactooz"],"files":[]},"headers":[],"relativePath":"de_de/1.21.1/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.1/translated/de_de/develop/getting-started/creating-a-project.md","lastUpdated":1761424914000}`);var l={name:`de_de/1.21.1/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Ein Projekt erstellen <a class="header-anchor" href="#h1" aria-label="Permalink to “Ein Projekt erstellen”">​</a></h1><p>Fabric bietet eine einfache Möglichkeit, ein neues Mod-Projekt mit dem Fabric Template Mod Generator zu erstellen - wenn du möchtest, kannst du ein neues Projekt auch manuell erstellen, indem du das Beispiel-Mod-Repository verwendest, dann solltest du den Abschnitt <a href="#manuelle-projekterstellung">Manuelle Projekterstellung</a> lesen.</p><h2 id="generating-a-project" tabindex="-1">Erstellung eines Projekts <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “Erstellung eines Projekts”">​</a></h2><p>Du kannst den <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric Vorlagen Mod Generator</a> verwenden, um ein neues Projekt für deinen Mod zu generrieren - du solltest die erforderlichen Felder ausfüllen, wie beispielsweise den Paketnamen und den Mod-Namen, sowie die Minecraft-Version, für die du entwickeln möchtest.</p><p>Der Paketname sollte klein geschrieben, durch Punkte getrennt und eindeutig sein, um Konflikte mit den Paketen anderer Programmierer zu vermeiden. Er ist typischerweise wie eine umgedrehte Internet-Domain formatiert, beispielsweise wie <code>com.example.example-mod</code>.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="Vorschau des Generators" loading="lazy"></p><p>Wenn du Kotlin verwenden, die offiziellen Mappings von Mojang anstelle der Yarn-Mappings nutzen oder Datengeneratoren hinzufügen möchtest, kannst du die entsprechenden Optionen im Abschnitt <code>Advanced Options</code> auswählen.</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Der Abschnitt &quot;Advanced options&quot;" loading="lazy"></p><p>Der Generator erstellt dann ein neues Projekt in Form einer ZIP-Datei für dich.</p><p>Du solltest diese ZIP-Datei an einem Ort deiner Wahl entpacken und dann den entpackten Ordner in IntelliJ IDEA öffnen:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="Aufforderung zum Öffnen des Projekts" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">Import des Projekts <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “Import des Projekts”">​</a></h2><p>Sobald du das Projekt in IntelliJ IDEA geöffnet hast, sollte IDEA automatisch die Gradle-Konfiguration des Projekts laden und die notwendigen Einrichtungsaufgaben durchführen.</p><p>Wenn du eine Benachrichtigung über ein Gradle-Build-Skript erhältst, solltest du auf die Schaltfläche <code>Import Gradle Project</code> klicken:</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle Aufforderung" loading="lazy"></p><p>Sobald das Projekt importiert wurde, solltest du die Dateien des Projekts im Projekt-Explorer sehen und mit der Entwicklung deines Mods beginnen können.</p><h2 id="manual-project-creation" tabindex="-1">Manuelle Projekterstellung <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “Manuelle Projekterstellung”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Du musst <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> installiert haben, um das Beispiel-Mod-Repository klonen zu können.</p></div><p>Wenn du den Fabric Vorlagen Mod Generator nicht verwenden kannst, kannst du ein neues Projekt manuell erstellen, indem du folgende Schritte befolgst.</p><p>Klone zunächst das Beispiel-Mod-Repository mit Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Dadurch wird das Repository in einen neuen Ordner mit dem Namen <code>my-mod-project</code> geklont.</p><p>Anschließend solltest du den Ordner <code>.git</code> aus dem geklonten Repository löschen und das Projekt in IntelliJ IDEA öffnen. Wenn der Ordner <code>.git</code> nicht angezeigt wird, solltest du die Option zur Anzeige versteckter Dateien in deinem Dateimanager aktivieren.</p><p>Sobald du das Projekt in IntelliJ IDEA geöffnet hast, sollte es automatisch die Gradle-Konfiguration des Projekts laden und die notwendigen Einrichtungsaufgaben durchführen.</p><p>Wie bereits erwähnt, solltest du, wenn du eine Benachrichtigung über ein Gradle-Build-Skript erhältst, auf die Schaltfläche <code>Import Gradle Project</code> klicken.</p><h3 id="modifying-the-template" tabindex="-1">Die Vorlage bearbeiten <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “Die Vorlage bearbeiten”">​</a></h3><p>Sobald das Projekt importiert wurde, solltest du die Details des Projekts so ändern, dass sie mit den Details deines Mods übereinstimmen:</p><ul><li>Ändere die Datei <code>gradle.properties</code> des Projekts, um die Eigenschaften <code>maven_group</code> und <code>archive_base_name</code> an die Details deines Mods anzupassen.</li><li>Ändere die Datei <code>fabric.mod.json</code>, um die Eigenschaften <code>id</code>, <code>name</code> und <code>description</code> an die Details deines Mods anzupassen.</li><li>Stelle sicher, dass die Versionen von Minecraft, die Mappings, der Loader und Loom - die alle über <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> abgefragt werden können - mit den Versionen übereinstimmen, die du ansprechen möchtest.</li></ul><p>Du kannst natürlich den Paketnamen und die Hauptklasse des Mods ändern, um die Details deines Mods anzupassen.</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};